; [AI] ===== REBOOT_MAIN ($0200) ================================================
; [AI] Prompt the user, wait for a key, then arm the 6502 to boot from floppy.
REBOOT_MAIN:
        LD DE,MSG_PRESS_RETURN           ; $0200  11 17 02   ; [AI] DE -> "PRESS RETURN TO BOOT$"
        LD C,$09                         ; $0203  0E 09       ; [AI] BDOS fn 9 = print $-terminated string
        CALL BDOS_VEC                    ; $0205  CD 05 00    ; [AI] print the prompt to the console
        LD C,$01                         ; $0208  0E 01       ; [AI] BDOS fn 1 = console input (wait for one key, echo); A = char
        CALL BDOS_VEC                    ; $020A  CD 05 00    ; [AI] block until the user presses a key (RETURN); key returned in A
        LD HL,APPLE_DISKII_SLOT6         ; $020D  21 00 C6    ; [AI] HL = $C600, Disk II slot-6 boot ROM entry
        LD (A_VEC),HL         ; $0210  22 D0 F3    ; [AI] publish the 6502 boot vector ($C600) to the host comm cell
        LD HL,(Z_CPU)          ; $0213  2A DE F3    ; [AI] HL = pointer the 6502 watches (from Z_CPU)
        LD (HL),A                        ; $0216  77          ; [AI] store the typed key there -> signals the 6502 to take over and boot
; [AI] No RET: the 6502 side now resets/boots from the floppy via $C600.

; [AI] ===== MSG_PRESS_RETURN ($0217) ===========================================
; [AI] The disassembler decoded this $-string as Z-80 instructions; the bytes are
; [AI]   really CR,LF,"PRESS RETURN TO BOOT",'$'. Do not edit -- the labels below
; [AI]   are kept so the LD DE / JR operands above resolve to the same bytes.
MSG_PRESS_RETURN:
        DEC C                            ; $0217  0D          ; [AI] 0D = CR
        LD A,(BC)                        ; $0218  0A          ; [AI] 0A = LF
        LD D,B                           ; $0219  50          ; [AI] 'P'
        LD D,D                           ; $021A  52          ; [AI] 'R'
        LD B,L                           ; $021B  45          ; [AI] 'E'
        LD D,E                           ; $021C  53          ; [AI] 'S'
        LD D,E                           ; $021D  53          ; [AI] 'S'
        JR NZ,MSG_SP_RETURN              ; $021E  20 52       ; [AI] ' ' (0x20) then 'R' (0x52)
        LD B,L                           ; $0220  45          ; [AI] 'E'
        LD D,H                           ; $0221  54          ; [AI] 'T'
        LD D,L                           ; $0222  55          ; [AI] 'U'
        LD D,D                           ; $0223  52          ; [AI] 'R'
        LD C,(HL)                        ; $0224  4E          ; [AI] 'N'
        JR NZ,MSG_SP_BOOT                ; $0225  20 54       ; [AI] ' ' (0x20) then 'T' (0x54)
        LD C,A                           ; $0227  4F          ; [AI] 'O'
        JR NZ,MSG_BOOT_OO                ; $0228  20 42       ; [AI] ' ' (0x20) then 'B' (0x42)
        LD C,A                           ; $022A  4F          ; [AI] 'O'
        LD C,A                           ; $022B  4F          ; [AI] 'O'
        LD D,H                           ; $022C  54          ; [AI] 'T'
        INC H                            ; $022D  24          ; [AI] '$' (0x24) -- BDOS fn 9 string terminator
; [AI] ===== EOF filler ($022E-$027F) ===========================================
; [AI] $1A (Ctrl-Z) padding to the end of the 384-byte image; CP/M's classic
; [AI]   end-of-file fill byte. Never executed; only the bytes matter.
EOF_FILL:
